  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Close-Grip_Bench_To_Skull_Crusher/Decline_Close-Grip_Bench_To_Skull_Crusher/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Decline_Close-Grip_Bench_To_Skull_Crusher/Decline_Close-Grip_Bench_To_Skull_Crusher/1.jpg"]', 
