  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/Dumbbell_Lying_One-Arm_Rear_Lateral_Raise/1.jpg"]', 
