  'beginner', 
  'compound', 
  'push', 
  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Extended_Range_One-Arm_Kettlebell_Floor_Press/Extended_Range_One-Arm_Kettlebell_Floor_Press/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Extended_Range_One-Arm_Kettlebell_Floor_Press/Extended_Range_One-Arm_Kettlebell_Floor_Press/1.jpg"]', 
