  'beginner', 
  'compound', 
  'static', 
  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Knee_To_Chest/One_Knee_To_Chest/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Knee_To_Chest/One_Knee_To_Chest/1.jpg"]', 
  NOW()
