  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Biceps/Seated_Biceps/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Seated_Biceps/Seated_Biceps/1.jpg"]', 
