  '["https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch/Snatch/0.jpg","https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Snatch/Snatch/1.jpg"]', 
